const rows = msg.payload;
if (!rows || rows.length === 0) {
    node.warn('config_zafra: sin resultados');
    return null;
}
const cfg = rows[0];

// fecha_inicio viene como Date de MySQL: 2026-05-18T03:00:00.000Z
const d = new Date(cfg.fecha_inicio);
const yyyy = d.getFullYear();
const mm   = String(d.getMonth() + 1).padStart(2, '0');
const dd   = String(d.getDate()).padStart(2, '0');

// Formatos que usan las queries SQL Server
global.set('zafra_inicio_dmY',    `${dd}/${mm}/${yyyy}`);   // '18/05/2026'
global.set('zafra_inicio_Ymd',    `${yyyy}-${mm}-${dd}`);   // '2026-05-18'
global.set('zafra_inicio_mes_Ymd',`${yyyy}-${mm}-01`);      // '2026-05-01'
global.set('zafra_anio',           cfg.anio);
global.set('zafra_nombre',         cfg.nombre_zafra);

node.log(`Config zafra cargada: ${cfg.nombre_zafra} | inicio: ${dd}/${mm}/${yyyy}`);
return null;
